SELECT * FROM user_follow
WHERE follower_id = #{userId}

    AND relation_type = #{relationType}

ORDER BY create_time DESC
LIMIT #{offset}, #{pageSize}

SELECT * FROM user_follow
WHERE following_id = #{userId}

    AND relation_type = #{relationType}

